// Main entry point — re-exports everything
export { Launcher } from "./components/launcher";
export { LauncherInput } from "./components/launcher-input";
export { LauncherSidebar } from "./components/launcher-sidebar";
export { LauncherResults } from "./components/launcher-results";
export { LauncherFooter } from "./components/launcher-footer";

export { createLauncherStore } from "./lib/launcher-store";
export type { LauncherState, LauncherStore } from "./lib/launcher-store";
export { searchItems, createFuseInstance, defaultWeights } from "./lib/launcher-search";
export type { SearchWeights } from "./lib/launcher-search";
export type { LauncherItem, NavigationLevel, Category } from "./lib/launcher-types";

import type { LauncherStore } from "../lib/launcher-store";
"use client";

import React, { useEffect, useMemo, useState } from "react";
import { CommandDialog, Command } from "@/components/ui/command";
import { LauncherInput } from "./launcher-input";
import { LauncherSidebar } from "./launcher-sidebar";
import { LauncherResults } from "./launcher-results";
import { LauncherFooter } from "./launcher-footer";
import type { Category } from "../lib/launcher-types";

interface LauncherProps {
  store: LauncherStore;
  categories?: Category[];
  branding?: {
    icon?: React.ReactNode;
    label?: string;
  };
}

export function Launcher({ store, categories, branding }: LauncherProps) {
  const open = store((s) => s.open);
  const setOpen = store((s) => s.setOpen);
  const popNavigation = store((s) => s.popNavigation);
  const navigationStack = store((s) => s.navigationStack);
  const query = store((s) => s.query);
  const selectedCategory = store((s) => s.selectedCategory);
  const recents = store((s) => s.recents);
  const favorites = store((s) => s.favorites);

  const breadcrumbs = useMemo(
    () => navigationStack.filter((l) => l.item).map((l) => l.item!.name),
    [navigationStack]
  );

  const displayResults = useMemo(
    () => store.getState().getDisplayResults(),
    [store, navigationStack, query, selectedCategory, recents, favorites]
  );

  const depth = navigationStack.length;

  const [cmdkValue, setCmdkValue] = useState("");

  // Auto-select first item when results change
  useEffect(() => {
    if (displayResults.length > 0) {
      setCmdkValue(`${depth}-${displayResults[0].id}-${displayResults[0].name}`);
    }
  }, [displayResults, depth]);

  // Refocus cmdk input after navigation changes
  useEffect(() => {
    if (!open) return;
    requestAnimationFrame(() => {
      const input = document.querySelector("[cmdk-input]") as HTMLInputElement;
      input?.focus();
    });
  }, [navigationStack, open]);

  // ⌘K global shortcut + Escape/Enter override
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        const currentOpen = store.getState().open;
        setOpen(!currentOpen);
        return;
      }

      const currentOpen = store.getState().open;
      if (!currentOpen) return;

      if (e.key === "Escape") {
        e.preventDefault();
        e.stopPropagation();
        const currentBreadcrumbs = store.getState().getBreadcrumbs();
        if (currentBreadcrumbs.length > 0) {
          store.getState().popNavigation();
        } else {
          setOpen(false);
        }
        return;
      }

      if (e.key === "Enter") {
        const selected = document.querySelector(
          '[cmdk-item][data-selected="true"]'
        ) as HTMLElement;
        if (selected) {
          e.preventDefault();
          selected.click();
        }
        return;
      }
    };

    document.addEventListener("keydown", handleKeyDown, true);
    return () => document.removeEventListener("keydown", handleKeyDown, true);
  }, [store, setOpen]);

  return (
    <CommandDialog
      open={open}
      onOpenChange={setOpen}
      className="top-[15%] max-h-[70vh] sm:max-w-[680px]"
    >
      <Command
        shouldFilter={false}
        value={cmdkValue}
        onValueChange={setCmdkValue}
        className="bg-popover border border-border flex flex-col max-h-[70vh]"
      >
        <LauncherInput store={store} branding={branding} />

        <div className="flex flex-1 min-h-0">
          <LauncherSidebar store={store} categories={categories} />
          <div
            role="region"
            aria-label="Results"
            className="flex-1 min-w-0 overflow-hidden"
          >
            <LauncherResults store={store} />
          </div>
        </div>

        <LauncherFooter store={store} branding={branding} />
      </Command>
    </CommandDialog>
  );
}

import type { LauncherStore } from "../lib/launcher-store";
"use client";

import React, { useMemo } from "react";
import { CommandInput } from "@/components/ui/command";
import { Badge } from "@/components/ui/badge";
import { Diamond } from "@phosphor-icons/react";

interface LauncherInputProps {
  store: LauncherStore;
  branding?: {
    icon?: React.ReactNode;
    label?: string;
  };
}

export function LauncherInput({ store, branding }: LauncherInputProps) {
  const query = store((s) => s.query);
  const setQuery = store((s) => s.setQuery);
  const resetNavigation = store((s) => s.resetNavigation);
  const popNavigation = store((s) => s.popNavigation);
  const setNavigationStack = store((s) => s.setNavigationStack);
  const navigationStack = store((s) => s.navigationStack);
  const breadcrumbs = useMemo(
    () => navigationStack.filter((l) => l.item).map((l) => l.item!.name),
    [navigationStack]
  );

  const navigateToBreadcrumb = (index: number) => {
    setNavigationStack((stack) => stack.slice(0, index + 2));
  };

  const defaultBranding = {
    icon: <Diamond size={12} weight="fill" className="text-primary/40" />,
    label: "launcher",
  };

  const activeBranding = branding || defaultBranding;

  return (
    <div className="flex items-center gap-2 px-3 py-2.5 border-b border-border">
      {/* Branding + breadcrumbs */}
      <div className="flex items-center gap-1.5 text-xs font-mono shrink-0">
        <button
          onClick={resetNavigation}
          className="flex items-center gap-1 text-muted-foreground hover:text-foreground transition-colors"
        >
          {activeBranding.icon}
          <span>{activeBranding.label}</span>
        </button>

        {breadcrumbs.map((name: string, index: number) => (
          <div key={index} className="flex items-center gap-1">
            <span className="text-muted-foreground">/</span>
            <Badge
              variant="secondary"
              className="cursor-pointer text-xs px-1.5 py-0 font-mono hover:bg-accent hover:text-accent-foreground transition-colors"
              onClick={() => navigateToBreadcrumb(index)}
            >
              {name}
            </Badge>
          </div>
        ))}
      </div>

      {/* Search */}
      <div className="flex-1 min-w-0">
        <CommandInput
          value={query}
          onValueChange={setQuery}
          placeholder={
            breadcrumbs.length > 0
              ? `Search ${breadcrumbs[breadcrumbs.length - 1]}...`
              : "Search..."
          }
          onKeyDown={(e) => {
            if (
              e.key === "Backspace" &&
              query === "" &&
              breadcrumbs.length > 0
            ) {
              e.preventDefault();
              popNavigation();
            }
          }}
          className="h-8 border-0 shadow-none focus-visible:ring-0"
        />
      </div>

      {/* Shortcut hints */}
      <div className="flex items-center gap-1.5 shrink-0">
        <kbd className="px-1.5 py-0.5 text-[11px] font-mono bg-muted text-muted-foreground border border-border">
          ⌘K
        </kbd>
      </div>
    </div>
  );
}

import type { LauncherStore } from "../lib/launcher-store";
"use client";

import React from "react";
import { Separator } from "@/components/ui/separator";
import {
  SquaresFour,
  ClockCounterClockwise,
  Star,
} from "@phosphor-icons/react";
import type { Icon } from "@phosphor-icons/react";
import type { Category } from "../lib/launcher-types";

interface LauncherSidebarProps {
  store: LauncherStore;
  categories?: Category[];
}

const defaultCategories: Category[] = [
  { id: "all", name: "All", icon: SquaresFour },
  { id: "__recent", name: "Recent", icon: ClockCounterClockwise },
  { id: "__favorites", name: "Favorites", icon: Star },
];

export function LauncherSidebar({ store, categories = defaultCategories }: LauncherSidebarProps) {
  const selectedCategory = store((s) => s.selectedCategory);
  const setSelectedCategory = store((s) => s.setSelectedCategory);

  return (
    <nav
      aria-label="Categories"
      className="w-[160px] border-r border-border py-1.5 overflow-y-auto launcher-scroll shrink-0"
    >
      {categories.map((cat, index) => {
        if (cat.isDivider) {
          return <Separator key={`div-${index}`} className="my-1.5 mx-3" />;
        }

        const Icon = cat.icon;
        const isActive =
          (cat.id === "all" && selectedCategory === null) ||
          selectedCategory === cat.id;

        return (
          <button
            key={cat.id}
            onClick={() =>
              setSelectedCategory(cat.id === "all" ? null : cat.id!)
            }
            className={`
              w-full px-3 py-1.5 flex items-center gap-2.5 text-left text-[13px] transition-colors cursor-pointer
              ${
                isActive
                  ? "bg-accent text-accent-foreground"
                  : "text-muted-foreground hover:text-foreground hover:bg-muted"
              }
            `}
          >
            {Icon && (
              <Icon
                size={15}
                weight={isActive ? "fill" : "regular"}
                className="shrink-0"
              />
            )}
            <span className="truncate">{cat.name}</span>
          </button>
        );
      })}
    </nav>
  );
}

import type { LauncherStore } from "../lib/launcher-store";
"use client";

import React, { memo } from "react";
import {
  CommandList,
  CommandGroup,
  CommandItem,
  CommandEmpty,
} from "@/components/ui/command";
import { CaretRight, ArrowSquareOut, Star, Sparkle } from "@phosphor-icons/react";
import type { LauncherItem } from "../lib/launcher-types";

const LauncherItemRow = memo(
  ({
    item,
    isFavorite,
    onSelect,
    onToggleFavorite,
    depth,
  }: {
    item: LauncherItem;
    isFavorite: boolean;
    onSelect: () => void;
    onToggleFavorite: (e: React.MouseEvent) => void;
    depth: number;
  }) => {
    const Icon = item.icon;
    const hasChildren = Boolean(item.children?.length);
    const isExternal = Boolean(item.url);

    return (
      <CommandItem
        value={`${depth}-${item.id}-${item.name}`}
        onSelect={onSelect}
        className="flex items-center justify-between px-3 py-2.5 cursor-pointer group"
      >
        <div className="flex items-center gap-3 flex-1 min-w-0">
          <Icon
            size={18}
            weight="regular"
            className="text-muted-foreground shrink-0"
          />
          <div className="flex-1 min-w-0">
            <div className="text-sm font-medium truncate">{item.name}</div>
            {item.description && (
              <div className="text-xs text-muted-foreground truncate">
                {item.description}
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center gap-2 shrink-0">
          <button
            onClick={onToggleFavorite}
            className={`p-1 transition-opacity ${
              isFavorite
                ? "opacity-100 text-chart-4"
                : "opacity-0 group-hover:opacity-60 hover:!opacity-100 text-muted-foreground"
            }`}
          >
            <Star size={14} weight={isFavorite ? "fill" : "regular"} />
          </button>

          {hasChildren && (
            <CaretRight size={14} className="text-muted-foreground" />
          )}
          {isExternal && (
            <ArrowSquareOut size={14} className="text-muted-foreground" />
          )}
        </div>
      </CommandItem>
    );
  }
);

LauncherItemRow.displayName = "LauncherItemRow";

interface LauncherResultsProps {
  store: LauncherStore;
}

export function LauncherResults({ store }: LauncherResultsProps) {
  const navigationStack = store((s) => s.navigationStack);
  const favorites = store((s) => s.favorites);
  const selectItem = store((s) => s.selectItem);
  const toggleFavorite = store((s) => s.toggleFavorite);
  const query = store((s) => s.query);
  const selectedCategory = store((s) => s.selectedCategory);
  const recents = store((s) => s.recents);
  const displayResults = React.useMemo(
    () => store.getState().getDisplayResults(),
    [store, navigationStack, query, selectedCategory, favorites, recents]
  );

  const depth = navigationStack.length;
  const favoritesSet = new Set(favorites);

  // Group results by category
  const groupedResults = React.useMemo(() => {
    const groups = new Map<string, LauncherItem[]>();
    for (const item of displayResults) {
      const cat = item.category;
      if (!groups.has(cat)) groups.set(cat, []);
      groups.get(cat)!.push(item);
    }
    return groups;
  }, [displayResults]);

  const handleToggleFavorite = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    toggleFavorite(id);
  };

  return (
    <CommandList className="flex-1 overflow-y-auto launcher-scroll max-h-none px-1 min-h-0">
      {displayResults.length === 0 ? (
        <CommandEmpty className="py-12 text-center">
          <Sparkle
            size={28}
            weight="duotone"
            className="mx-auto mb-2 text-muted-foreground"
          />
          <p className="text-sm text-muted-foreground">No results found</p>
        </CommandEmpty>
      ) : (
        Array.from(groupedResults.entries()).map(([category, items]) => (
          <CommandGroup key={category} heading={category} className="mb-2">
            {items.map((item) => (
              <LauncherItemRow
                key={`${depth}-${item.id}`}
                item={item}
                isFavorite={favoritesSet.has(item.id)}
                onSelect={() => selectItem(item)}
                onToggleFavorite={(e) => handleToggleFavorite(e, item.id)}
                depth={depth}
              />
            ))}
          </CommandGroup>
        ))
      )}
    </CommandList>
  );
}

