import { create, type StateCreator, type StoreApi, type UseBoundStore } from "zustand";
import { persist } from "zustand/middleware";
import type { LauncherItem, NavigationLevel } from "./launcher-types";
import { searchItems, flattenItems, defaultWeights, type SearchWeights } from "./launcher-search";

interface LauncherConfig {
  manifest: LauncherItem[];
  searchWeights?: SearchWeights;
  persistKey?: string;
}

function getAllItems(items: LauncherItem[]): LauncherItem[] {
  const result: LauncherItem[] = [];
  function traverse(items: LauncherItem[]) {
    items.forEach((item) => {
      result.push(item);
      if (item.children) traverse(item.children);
    });
  }
  traverse(items);
  return result;
}

function buildNavigationPath(
  targetItem: LauncherItem,
  manifest: LauncherItem[]
): NavigationLevel[] {
  const path: NavigationLevel[] = [{ item: null, results: manifest }];

  function findPath(
    items: LauncherItem[],
    target: string
  ): LauncherItem[] | null {
    for (const item of items) {
      if (item.id === target) return [item];
      if (item.children) {
        const sub = findPath(item.children, target);
        if (sub) return [item, ...sub];
      }
    }
    return null;
  }

  const ancestry = findPath(manifest, targetItem.id);
  if (ancestry) {
    for (const ancestor of ancestry) {
      if (ancestor.children) {
        path.push({ item: ancestor, results: ancestor.children });
      }
    }
  }

  return path;
}

export interface LauncherState {
  open: boolean;
  query: string;
  selectedCategory: string | null;
  navigationStack: NavigationLevel[];
  recents: string[];
  favorites: string[];

  setOpen: (open: boolean) => void;
  setQuery: (query: string) => void;
  setSelectedCategory: (category: string | null) => void;
  selectItem: (item: LauncherItem) => void;
  pushNavigation: (item: LauncherItem) => void;
  popNavigation: () => void;
  resetNavigation: () => void;
  toggleFavorite: (id: string) => void;
  setNavigationStack: (
    updater:
      | NavigationLevel[]
      | ((prev: NavigationLevel[]) => NavigationLevel[])
  ) => void;

  getBreadcrumbs: () => string[];
  getDisplayResults: () => LauncherItem[];
}

/** The typed store hook returned by createLauncherStore */
export type LauncherStore = UseBoundStore<StoreApi<LauncherState>>;

export function createLauncherStore(config: LauncherConfig): LauncherStore {
  const { manifest, searchWeights = defaultWeights, persistKey = "launcher-storage" } = config;

  const storeDefinition: StateCreator<LauncherState, [], []> = (set, get) => ({
    open: false,
    query: "",
    selectedCategory: null,
    navigationStack: [{ item: null, results: manifest }],
    recents: [],
    favorites: [],

    setOpen: (open) => set({ open }),
    setQuery: (query) => set({ query }),

    setSelectedCategory: (category) =>
      set({
        selectedCategory: category,
        navigationStack: [{ item: null, results: manifest }],
        query: "",
      }),

    selectItem: (item) => {
      const { recents } = get();
      const newRecents = [
        item.id,
        ...recents.filter((id) => id !== item.id),
      ].slice(0, 20);

      if (item.children) {
        set({
          navigationStack: buildNavigationPath(item, manifest),
          query: "",
          selectedCategory: null,
          recents: newRecents,
        });
      } else {
        if (item.url) window.open(item.url, "_blank");
        if (item.action) item.action();
        set({ open: false, recents: newRecents });
      }
    },

    pushNavigation: (item) => {
      if (!item.children) return;
      set((state) => ({
        navigationStack: [
          ...state.navigationStack,
          { item, results: item.children! },
        ],
        query: "",
      }));
    },

    popNavigation: () => {
      const { navigationStack } = get();
      if (navigationStack.length > 1) {
        set({ navigationStack: navigationStack.slice(0, -1), query: "" });
      } else {
        set({ open: false });
      }
    },

    resetNavigation: () =>
      set({
        navigationStack: [{ item: null, results: manifest }],
        query: "",
        selectedCategory: null,
      }),

    toggleFavorite: (id) =>
      set((state) => ({
        favorites: state.favorites.includes(id)
          ? state.favorites.filter((f) => f !== id)
          : [...state.favorites, id],
      })),

    setNavigationStack: (updater) =>
      set((state) => ({
        navigationStack:
          typeof updater === "function"
            ? updater(state.navigationStack)
            : updater,
        query: "",
      })),

    getBreadcrumbs: () =>
      get()
        .navigationStack.filter((l) => l.item)
        .map((l) => l.item!.name),

    getDisplayResults: () => {
      const { navigationStack, query, selectedCategory, recents, favorites } =
        get();
      const currentLevel = navigationStack[navigationStack.length - 1];
      const baseResults = currentLevel.results;

      if (selectedCategory === "__recent") {
        const allItems = getAllItems(manifest);
        return recents
          .map((id) => allItems.find((i) => i.id === id))
          .filter(Boolean) as LauncherItem[];
      }
      if (selectedCategory === "__favorites") {
        const allItems = getAllItems(manifest);
        return favorites
          .map((id) => allItems.find((i) => i.id === id))
          .filter(Boolean) as LauncherItem[];
      }
      if (query.trim()) {
        // When drilled down, search all descendants (not just immediate children)
        const searchPool = currentLevel.item
          ? flattenItems(baseResults)
          : baseResults;
        return searchItems(query, searchPool, recents, favorites, searchWeights);
      }
      if (selectedCategory && currentLevel.item === null)
        return baseResults.filter((i) => i.category === selectedCategory);
      return baseResults;
    },
  });

  // Persist middleware wraps the store for localStorage — disabled in test
  const isTest =
    typeof process !== "undefined" && process.env.NODE_ENV === "test";

  return isTest
    ? create<LauncherState>()(storeDefinition)
    : create<LauncherState>()(
        persist(storeDefinition, {
          name: persistKey,
          partialize: (state) => ({
            recents: state.recents,
            favorites: state.favorites,
          }),
        })
      );
}

import { Icon } from "@phosphor-icons/react";

export interface LauncherItem {
  id: string;
  name: string;
  description?: string;
  icon: Icon;
  category: string;
  tags: string[];
  aliases?: string[];
  keywords?: string[];
  prefixes?: string[];
  children?: LauncherItem[];
  action?: () => void;
  url?: string;
}

export interface NavigationLevel {
  item: LauncherItem | null; // null for root
  results: LauncherItem[];
}

export interface Category {
  id: string;
  name: string;
  icon?: Icon;
  isDivider?: boolean;
}

import Fuse from "fuse.js";
import { LauncherItem } from "./launcher-types";

export interface SearchWeights {
  name: number;
  aliases: number;
  keywords: number;
  tags: number;
  description: number;
}

export const defaultWeights: SearchWeights = {
  name: 3.0,
  aliases: 2.0,
  keywords: 1.5,
  tags: 1.0,
  description: 0.5,
};

export function createFuseInstance(items: LauncherItem[], weights = defaultWeights) {
  return new Fuse(items, {
    keys: [
      { name: "name", weight: weights.name },
      { name: "aliases", weight: weights.aliases },
      { name: "keywords", weight: weights.keywords },
      { name: "tags", weight: weights.tags },
      { name: "description", weight: weights.description },
    ],
    threshold: 0.4,
    includeScore: true,
    ignoreLocation: true,
  });
}

/**
 * Flatten an item tree into a flat list (all descendants).
 */
export function flattenItems(items: LauncherItem[]): LauncherItem[] {
  const result: LauncherItem[] = [];
  for (const item of items) {
    result.push(item);
    if (item.children) {
      result.push(...flattenItems(item.children));
    }
  }
  return result;
}

/**
 * Parse prefix filters from query. E.g. "nfl:panthers" → { prefix: "nfl:", query: "panthers" }
 */
function parsePrefixFilter(
  query: string,
  allItems: LauncherItem[]
): { filteredItems: LauncherItem[] | null; cleanQuery: string } {
  const colonIdx = query.indexOf(":");
  if (colonIdx < 1 || colonIdx > 10) return { filteredItems: null, cleanQuery: query };

  const prefix = query.slice(0, colonIdx + 1).toLowerCase();
  const cleanQuery = query.slice(colonIdx + 1).trim();

  for (const item of allItems) {
    if (item.prefixes?.some((p) => p.toLowerCase() === prefix)) {
      return {
        filteredItems: item.children ?? [item],
        cleanQuery,
      };
    }
  }

  return { filteredItems: null, cleanQuery: query };
}

export function searchItems(
  query: string,
  items: LauncherItem[],
  recents: string[] = [],
  favorites: string[] = [],
  weights = defaultWeights
): LauncherItem[] {
  if (!query.trim()) {
    // Return recents + favorites when no query
    const recentItems = recents
      .map((id) => items.find((item) => item.id === id))
      .filter(Boolean) as LauncherItem[];

    const favoriteItems = favorites
      .map((id) => items.find((item) => item.id === id))
      .filter(Boolean) as LauncherItem[];

    // Combine and dedupe
    const seen = new Set<string>();
    const combined: LauncherItem[] = [];

    [...recentItems, ...favoriteItems].forEach((item) => {
      if (!seen.has(item.id)) {
        seen.add(item.id);
        combined.push(item);
      }
    });

    return combined.length > 0 ? combined : items.slice(0, 10);
  }

  // Check for prefix filter (e.g. "nfl:panthers")
  const { filteredItems, cleanQuery } = parsePrefixFilter(query, items);
  const searchPool = filteredItems ?? items;
  const searchQuery = filteredItems ? cleanQuery : query;

  // If prefix matched but no remaining query, return all items in that scope
  if (filteredItems && !searchQuery.trim()) {
    return searchPool;
  }

  const fuse = createFuseInstance(searchPool, weights);
  const results = fuse.search(searchQuery || query);

  // Sort by exact match > starts with > fuzzy score
  return results
    .map((result) => {
      const item = result.item;
      const lowerQuery = query.toLowerCase();
      const lowerName = item.name.toLowerCase();

      let priority = 0;

      // Exact match
      if (lowerName === lowerQuery) {
        priority = 1000;
      }
      // Starts with
      else if (lowerName.startsWith(lowerQuery)) {
        priority = 500;
      }
      // Fuzzy score (inverse - lower is better)
      else {
        priority = 100 - (result.score || 0) * 100;
      }

      // Boost for recents
      if (recents.includes(item.id)) {
        priority += 50;
      }

      // Boost for favorites
      if (favorites.includes(item.id)) {
        priority += 100;
      }

      return { item, priority };
    })
    .sort((a, b) => b.priority - a.priority)
    .map((result) => result.item);
}
